-- Payroll tables and imported seed data from PAYROLL_2026.xlsx
-- Source workbook: F:/OneDrive/JJFS/Juja Brew & Bites/Visayas Ave., Pasong Tamo/Finance/PAYROLL_2026.xlsx

create table if not exists public.payroll_employees (
  id text primary key,
  employee_no text unique,
  full_name text not null unique,
  default_daily_rate numeric(12, 2) not null default 0,
  role text default 'staff',
  active boolean not null default true,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

create table if not exists public.payroll_periods (
  id text primary key,
  label text not null,
  source_sheet text unique,
  period_start date,
  period_end date,
  pay_date date,
  status text not null default 'draft' check (status in ('draft', 'approved', 'paid', 'void')),
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

create table if not exists public.payroll_entries (
  id text primary key,
  period_id text not null references public.payroll_periods(id) on delete cascade,
  employee_id text not null references public.payroll_employees(id) on delete restrict,
  daily_rate numeric(12, 2) not null default 0,
  days_worked numeric(8, 2) not null default 0,
  overtime_hours numeric(8, 2) not null default 0,
  overtime_rate numeric(12, 4) not null default 0,
  absent_days numeric(8, 2) not null default 0,
  late_minutes numeric(10, 2) not null default 0,
  late_rate_per_minute numeric(12, 6) not null default 0,
  undertime_minutes numeric(10, 2) not null default 0,
  undertime_rate_per_minute numeric(12, 6) not null default 0,
  allowance_15th numeric(12, 2) not null default 0,
  allowance_30th numeric(12, 2) not null default 0,
  cash_advance_deduction numeric(12, 2) not null default 0,
  gross_total numeric(12, 2) not null default 0,
  deduction_total numeric(12, 2) not null default 0,
  net_total numeric(12, 2) not null default 0,
  status text not null default 'draft' check (status in ('draft', 'approved', 'paid', 'void')),
  source_sheet text,
  notes text,
  generated_at timestamptz,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now(),
  unique (period_id, employee_id)
);

create table if not exists public.payroll_attendance (
  id text primary key,
  period_id text not null references public.payroll_periods(id) on delete cascade,
  employee_id text not null references public.payroll_employees(id) on delete restrict,
  work_date date not null,
  schedule_in text,
  schedule_out text,
  actual_in text,
  actual_out text,
  late_minutes numeric(10, 2) not null default 0,
  undertime_minutes numeric(10, 2) not null default 0,
  overtime_hours numeric(8, 2) not null default 0,
  status text not null default 'blank',
  notes text,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now(),
  unique (period_id, employee_id, work_date)
);

create table if not exists public.payroll_schedules (
  id text primary key,
  period_id text not null references public.payroll_periods(id) on delete cascade,
  employee_id text not null references public.payroll_employees(id) on delete restrict,
  work_date date not null,
  schedule_in text,
  schedule_out text,
  status text not null default 'scheduled' check (status in ('scheduled', 'rest_day', 'closed')),
  notes text,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now(),
  unique (period_id, employee_id, work_date)
);

create table if not exists public.payroll_cash_advances (
  id text primary key,
  employee_id text not null references public.payroll_employees(id) on delete restrict,
  advance_date date not null default current_date,
  amount numeric(12, 2) not null default 0,
  reason text,
  status text not null default 'active' check (status in ('active', 'paid', 'void')),
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

create table if not exists public.payroll_cash_advance_repayments (
  id text primary key,
  cash_advance_id text not null references public.payroll_cash_advances(id) on delete cascade,
  employee_id text not null references public.payroll_employees(id) on delete restrict,
  period_id text references public.payroll_periods(id) on delete set null,
  payment_date date not null default current_date,
  amount numeric(12, 2) not null default 0,
  method text not null default 'payroll deduction',
  notes text,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

alter table public.payroll_employees
  add column if not exists employee_no text;

create unique index if not exists payroll_employees_employee_no_key
  on public.payroll_employees(employee_no)
  where employee_no is not null;

alter table public.payroll_entries
  add column if not exists cash_advance_deduction numeric(12, 2) not null default 0,
  add column if not exists generated_at timestamptz;

alter table public.payroll_attendance
  add column if not exists notes text;

create index if not exists payroll_entries_period_idx on public.payroll_entries(period_id);
create index if not exists payroll_entries_employee_idx on public.payroll_entries(employee_id);
create index if not exists payroll_attendance_period_employee_idx on public.payroll_attendance(period_id, employee_id);
create index if not exists payroll_schedules_period_employee_idx on public.payroll_schedules(period_id, employee_id);
create index if not exists payroll_cash_advances_employee_idx on public.payroll_cash_advances(employee_id);
create index if not exists payroll_cash_advance_repayments_advance_idx on public.payroll_cash_advance_repayments(cash_advance_id);

alter table public.payroll_employees enable row level security;
drop policy if exists "payroll_employees_admin_all" on public.payroll_employees;
create policy "payroll_employees_admin_all"
  on public.payroll_employees
  for all
  to authenticated
  using (exists (select 1 from public.profiles p where p.id = auth.uid() and p.role in ('admin', 'super_admin')))
  with check (exists (select 1 from public.profiles p where p.id = auth.uid() and p.role in ('admin', 'super_admin')));
grant select, insert, update, delete on public.payroll_employees to authenticated;

