on conflict (id) do update set full_name = excluded.full_name, default_daily_rate = excluded.default_daily_rate, updated_at = now();

update public.payroll_employees e
set employee_no = seed.employee_no
from (values
  ('cindy-malagueno', 'EMP-003'),
  ('lyca-amparado', 'EMP-007'),
  ('mark-lester-arce', 'EMP-002'),
  ('mary-kristine-bagayawa', 'EMP-008'),
  ('mecaila-amparado', 'EMP-006'),
  ('norilyn-hernandez', 'EMP-004'),
  ('reinalyn-abarcar', 'EMP-001'),
  ('richel-amparado', 'EMP-005')
) as seed(id, employee_no)
where e.id = seed.id
  and (e.employee_no is null or e.employee_no = seed.employee_no);

on conflict (id) do update set label = excluded.label, source_sheet = excluded.source_sheet, period_start = excluded.period_start, period_end = excluded.period_end, pay_date = excluded.pay_date, updated_at = now();

on conflict (id) do update set daily_rate = excluded.daily_rate, days_worked = excluded.days_worked, overtime_hours = excluded.overtime_hours, overtime_rate = excluded.overtime_rate, absent_days = excluded.absent_days, late_minutes = excluded.late_minutes, late_rate_per_minute = excluded.late_rate_per_minute, undertime_minutes = excluded.undertime_minutes, undertime_rate_per_minute = excluded.undertime_rate_per_minute, allowance_15th = excluded.allowance_15th, allowance_30th = excluded.allowance_30th, gross_total = excluded.gross_total, deduction_total = excluded.deduction_total, net_total = excluded.net_total, source_sheet = excluded.source_sheet, updated_at = now();

on conflict (id) do update set schedule_in = excluded.schedule_in, schedule_out = excluded.schedule_out, actual_in = excluded.actual_in, actual_out = excluded.actual_out, late_minutes = excluded.late_minutes, undertime_minutes = excluded.undertime_minutes, overtime_hours = excluded.overtime_hours, status = excluded.status, updated_at = now();

